#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn cache_returns_same_result() {
        let mut cache = MeasureCache::new(100);
        let widget_id = WidgetId(42);
        let available = Size::new(80, 24);

        let mut call_count = 0;
        let compute = || {
            call_count += 1;
            SizeConstraints { min: Size::new(10, 1), preferred: Size::new(50, 5), max: None }
        };

        let r1 = cache.get_or_compute(widget_id, available, compute);
        let r2 = cache.get_or_compute(widget_id, available, || panic!("should not call"));

        assert_eq!(r1, r2);
        assert_eq!(call_count, 1); // Only called once
    }

    #[test]
    fn different_size_is_cache_miss() {
        let mut cache = MeasureCache::new(100);
        let widget_id = WidgetId(42);

        let mut call_count = 0;
        let compute = || {
            call_count += 1;
            SizeConstraints { min: Size::ZERO, preferred: Size::new(call_count as u16, 1), max: None }
        };

        cache.get_or_compute(widget_id, Size::new(80, 24), compute);
        cache.get_or_compute(widget_id, Size::new(120, 40), compute);

        assert_eq!(call_count, 2); // Called twice for different sizes
    }

    #[test]
    fn invalidation_clears_cache() {
        let mut cache = MeasureCache::new(100);
        let widget_id = WidgetId(42);
        let available = Size::new(80, 24);

        let mut call_count = 0;
        let compute = || {
            call_count += 1;
            SizeConstraints::ZERO
        };

        cache.get_or_compute(widget_id, available, compute);
        cache.invalidate_all();
        cache.get_or_compute(widget_id, available, compute);

        assert_eq!(call_count, 2); // Re-computed after invalidation
    }

    #[test]
    fn lru_eviction_works() {
        let mut cache = MeasureCache::new(2); // Small cache

        cache.get_or_compute(WidgetId(1), Size::new(10, 10), || SizeConstraints::ZERO);
        cache.get_or_compute(WidgetId(2), Size::new(10, 10), || SizeConstraints::ZERO);
        cache.get_or_compute(WidgetId(1), Size::new(10, 10), || panic!("should hit"));
        cache.get_or_compute(WidgetId(3), Size::new(10, 10), || SizeConstraints::ZERO);

        // WidgetId(2) should be evicted (least recently used)
        // WidgetId(1) was accessed twice, WidgetId(3) is new
        assert_eq!(cache.entries.len(), 2);
    }

    #[test]
    fn stats_track_hits_and_misses() {
        let mut cache = MeasureCache::new(100);

        cache.get_or_compute(WidgetId(1), Size::new(10, 10), || SizeConstraints::ZERO);
        cache.get_or_compute(WidgetId(1), Size::new(10, 10), || panic!("hit"));
        cache.get_or_compute(WidgetId(2), Size::new(10, 10), || SizeConstraints::ZERO);

        let stats = cache.stats();
        assert_eq!(stats.hits, 1);
        assert_eq!(stats.misses, 2);
        assert!((stats.hit_rate - 0.333).abs() < 0.01);
    }
