    fn block_measure_borders_only() {
        let b = Block::default().borders(Borders::ALL);
        let c = b.measure(Size::new(80, 24));
        assert_eq!(c.min, Size::new(2, 2)); // Border chrome only
    }

    #[test]
    fn block_measure_with_inner_content() {
        let inner = Paragraph::new("Hello"); // 5 chars
        let b = Block::default().borders(Borders::ALL).inner(inner);
        let c = b.measure(Size::new(80, 24));
        assert_eq!(c.preferred.width, 7); // 5 + 2 borders
        assert_eq!(c.preferred.height, 3); // 1 + 2 borders
    }

    #[test]
    fn block_measure_with_title() {
        let b = Block::default().borders(Borders::ALL).title("My Title");
        let c = b.measure(Size::new(80, 24));
        assert!(c.min.width >= 10); // Title + borders
    }

    // === List ===
    #[test]
    fn list_measure_aggregates_heights() {
        let items = vec![
            Paragraph::new("Line 1"),
            Paragraph::new("Line 2"),
            Paragraph::new("Line 3"),
        ];
        let list = List::new(items);
        let c = list.measure(Size::new(80, 24));
        assert_eq!(c.preferred.height, 3);
    }

    #[test]
    fn list_empty_is_zero() {
        let list: List<Paragraph> = List::new(vec![]);
        let c = list.measure(Size::MAX);
        assert_eq!(c, SizeConstraints::ZERO);
        assert!(!list.has_intrinsic_size());
    }

    // === Table ===
    #[test]
    fn table_measure_column_widths() {
        let rows = vec![
            Row::new(["A", "BB", "CCC"]),
            Row::new(["DDDD", "E", "F"]),
        ];
        let table = Table::new(rows, [Constraint::FitContent; 3]);
        let c = table.measure(Size::MAX);
        // Column widths: 4, 2, 3
        assert!(c.preferred.width >= 9);
    }

    // === Edge Cases ===
    #[test]
    fn measure_zero_available_no_panic() {
        let p = Paragraph::new("Some text");
        let c = p.measure(Size::ZERO);
        // Should return min_size, not panic
        assert!(c.min.width > 0 || c.preferred == Size::ZERO);
    }

    #[test]
    fn measure_max_available_no_overflow() {
        let p = Paragraph::new("text");
        let c = p.measure(Size::MAX);
        assert!(c.preferred.width < u16::MAX);
    }
