### 2. Property Tests (using proptest)
```rust
mod property_tests {
    use proptest::prelude::*;

    fn size_strategy() -> impl Strategy<Value = Size> {
        (0u16..500, 0u16..200).prop_map(|(w, h)| Size::new(w, h))
    }

    fn text_strategy() -> impl Strategy<Value = String> {
        "[a-zA-Z0-9 ]{0,200}"
    }

    proptest! {
        #![proptest_config(ProptestConfig::with_cases(1000))]

        // Invariant 1: min <= preferred
        #[test]
        fn invariant_min_le_preferred(text in text_strategy(), available in size_strategy()) {
            let p = Paragraph::new(&text);
            let c = p.measure(available);

            prop_assert!(c.min.width <= c.preferred.width,
                "min.width {} > preferred.width {}", c.min.width, c.preferred.width);
            prop_assert!(c.min.height <= c.preferred.height,
                "min.height {} > preferred.height {}", c.min.height, c.preferred.height);
        }

        // Invariant 2: preferred <= max (when max exists)
        #[test]
        fn invariant_preferred_le_max(text in text_strategy(), available in size_strategy()) {
            let p = Paragraph::new(&text);
            let c = p.measure(available);

            if let Some(max) = c.max {
                prop_assert!(c.preferred.width <= max.width,
                    "preferred.width {} > max.width {}", c.preferred.width, max.width);
                prop_assert!(c.preferred.height <= max.height,
                    "preferred.height {} > max.height {}", c.preferred.height, max.height);
            }
        }

        // Invariant 3: measure is pure
        #[test]
        fn invariant_measure_is_pure(text in text_strategy(), available in size_strategy()) {
            let p = Paragraph::new(&text);
            let c1 = p.measure(available);
            let c2 = p.measure(available);
            prop_assert_eq!(c1, c2, "measure() not pure: {:?} != {:?}", c1, c2);
        }

        // Invariant 4: min_size is constant
        #[test]
        fn invariant_min_size_constant(text in text_strategy()) {
            let p = Paragraph::new(&text);
            let c1 = p.measure(Size::new(10, 10));
            let c2 = p.measure(Size::new(100, 100));
            prop_assert_eq!(c1.min, c2.min, "min_size varies: {:?} vs {:?}", c1.min, c2.min);
        }

        // Invariant 5: height monotonic with width (for wrapping)
        #[test]
        fn invariant_height_monotonic_with_width(
            text in text_strategy(),
            w1 in 1u16..100,
            w2 in 1u16..100,
        ) {
            let p = Paragraph::new(&text);
            let c1 = p.measure(Size::new(w1, 1000));
            let c2 = p.measure(Size::new(w2, 1000));

            // Wider available -> same or fewer lines
            if w2 > w1 {
                prop_assert!(c2.preferred.height <= c1.preferred.height,
                    "height increased with width: w1={} h1={}, w2={} h2={}",
                    w1, c1.preferred.height, w2, c2.preferred.height);
            }
        }

        // Invariant 6: clamp is idempotent
        #[test]
        fn invariant_clamp_idempotent(
            min_w in 1u16..20, min_h in 1u16..10,
            pref_w in 20u16..100, pref_h in 10u16..50,
            input_w in 0u16..200, input_h in 0u16..100,
        ) {
            let c = SizeConstraints {
                min: Size::new(min_w, min_h),
                preferred: Size::new(pref_w, pref_h),
                max: Some(Size::new(pref_w + 50, pref_h + 20)),
            };
            let input = Size::new(input_w, input_h);
            let clamped = c.clamp(input);
            let double_clamped = c.clamp(clamped);
            prop_assert_eq!(clamped, double_clamped);
        }
    }
}
