fn render_adaptive_sidebar(&self, frame: &mut Frame, area: Rect) {
    let is_narrow = area.width < 60;

    let layout = Layout::horizontal()
        .constraints([
            // Sidebar: FitContent in narrow, fixed in wide
            if is_narrow {
                Constraint::FitContent
            } else {
                Constraint::Fixed(20)
            },
            Constraint::Fill,
        ]);

    let [sidebar_area, main_area] = layout.split(area);

    let sidebar_items = if is_narrow {
        vec!["📊", "⚙", "?"] // Icons only
    } else {
        vec!["📊 Dashboard", "⚙ Settings", "? Help"]
    };

    let sidebar = List::new(sidebar_items);
    frame.render_widget(sidebar, sidebar_area);

    // Main content...
}
